SELECT p.id, p.board_id, b.board_code, b.board_name, p.title, p.writer_id, u.name AS writer_name, u.username AS writer_username, p.view_count, p.is_notice, p.is_secret, p.created_at, p.created_by, p.updated_at, p.updated_by, p.deleted, (SELECT COUNT(*) FROM board_comment c WHERE c.post_id = p.id AND c.deleted = 0) AS comment_count, (SELECT COUNT(*) FROM file f WHERE f.ref_type = 'POST' AND f.ref_id = p.id AND f.deleted = 0) AS file_count FROM board_post p INNER JOIN board b ON p.board_id = b.id LEFT JOIN user u ON p.writer_id = u.id WHERE p.board_id IN
#{boardId}
AND p.deleted = 0 AND p.is_notice = 0 AND p.is_secret = 0 ORDER BY p.${sortField} ${sortOrder} LIMIT #{size}
